package day1;

public class Program3_DatatypeExample {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		boolean  result = true;// take 1 bit
		System.out.println(result);

		byte ans = 127; // take 1 byte
		System.out.println(ans);
		
		short  data = 32000;// take 2 bytes
		System.out.println(data);
		
		char  alpha = 'A'; // take 1 bytes
		System.out.println(alpha);
		
        float marks =  912.34559F;// take 4 bytes
		System.out.println(marks);
 
		double  marks2 = 912.34559333333344443333334444444444444444444444444444;// take 8 bytes
		System.out.println(marks2);
		  
		long  number = 1234568921L;// takes 8 bytes
		System.out.println(number);
		

	}
}
